data "aws_outposts_outpost" "factory" {
  name = "my-factory-outpost"
}

# Subnet on the Outpost
resource "aws_subnet" "outpost_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.10.0/24"
  outpost_arn       = data.aws_outposts_outpost.factory.arn
  availability_zone = data.aws_outposts_outpost.factory.availability_zone
}

# LGW route for on-premises traffic
resource "aws_route" "to_onprem" {
  route_table_id         = aws_route_table.outpost.id
  destination_cidr_block = "10.1.0.0/16"
  local_gateway_id       = data.aws_outposts_outpost.factory.local_gateway_id
}

# EC2 on Outpost
resource "aws_instance" "edge_compute" {
  ami           = "ami-0abcdef1234567890"
  instance_type = "m5.xlarge"
  subnet_id     = aws_subnet.outpost_subnet.id
  tags = { Name = "factory-edge-compute" }
}

# Route 53 failover for Outpost HA
resource "aws_route53_record" "primary" {
  zone_id = var.hosted_zone_id
  name    = "api.example.com"
  type    = "A"
  set_identifier = "outpost-primary"
  failover_routing_policy { type = "PRIMARY" }
  health_check_id = aws_route53_health_check.outpost_alb.id
  alias {
    name                   = aws_lb.outpost_alb.dns_name
    zone_id                = aws_lb.outpost_alb.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "secondary" {
  zone_id = var.hosted_zone_id
  name    = "api.example.com"
  type    = "A"
  set_identifier = "region-secondary"
  failover_routing_policy { type = "SECONDARY" }
  alias {
    name                   = aws_lb.region_alb.dns_name
    zone_id                = aws_lb.region_alb.zone_id
    evaluate_target_health = true
  }
}
